Here's a modern MSTest test class for `PriceCalculator` using both `[DataRow]` and `[DynamicData]` with ValueTuples:

```csharp
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // ─── CalculateTotal: DataRow for simple inline cases ───

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice")]
    [DataRow(10.00, -1, 0.10, "quantity")]
    [DataRow(10.00, 1, -0.01, "taxRate")]
    [DataRow(10.00, 1, 1.01, "taxRate")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // ─── ApplyDiscount: DynamicData with ValueTuples for type safety ───

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountValidCases))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountValidCases =>
    [
        (100m, 0m, 100m),
        (100m, 10m, 90m),
        (100m, 50m, 50m),
        (100m, 100m, 0m),
        (200m, 25m, 150m),
        (59.99m, 15m, 50.9915m),
    ];

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountInvalidCases))]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> ApplyDiscountInvalidCases =>
    [
        (100m, -1m),
        (100m, 100.01m),
        (50m, -0.01m),
    ];
}
```

**Key patterns used:**

- **`[DataRow]`** — for `CalculateTotal` where params are simple primitives (`double` cast to `decimal` since `DataRow` doesn't support `decimal` literals)
- **`[DynamicData]` with ValueTuples** (MSTest 3.7+) — for `ApplyDiscount` providing type safety and `decimal` support directly
- **`sealed` class**, AAA structure, `MethodName_Scenario_Expected` naming
- **`Assert.ThrowsExactly`** with `ParamName` verification for invalid input paths
- **`DisplayName`** on `DataRow` for readable test output
